PREFIX up:<http://purl.uniprot.org/core/>
PREFIX rdfs:<http://www.w3.org/2000/01/rdf-schema#>
SELECT ?protein ?db ?detail
FROM <http://uniprot.org>
WHERE
{ ?protein up:reviewed true ;
  a up:Protein ;
  rdfs:seeAlso ?db .
  ?db up:database <http://purl.uniprot.org/database/MGI>
  OPTIONAL { ?db rdfs:comment ?detail }
}
LIMIT 1

